script.js:
const {
  gsap: {
    registerPlugin,
    set,
    to,
    timeline,
    delayedCall,
    utils: { random } },

  MorphSVGPlugin,
  Draggable } =
window;
registerPlugin(MorphSVGPlugin);

// Used to calculate distance of "tug"
let startX;
let startY;

const CORD_DURATION = 0.1;
const INPUT = document.querySelector('#light-mode');
const ARMS = document.querySelectorAll('.bear__arm');
const PAW = document.querySelector('.bear__paw');
const CORDS = document.querySelectorAll('.toggle-scene__cord');
const HIT = document.querySelector('.toggle-scene__hit-spot');
const DUMMY = document.querySelector('.toggle-scene__dummy-cord');
const DUMMY_CORD = document.querySelector('.toggle-scene__dummy-cord line');
const PROXY = document.createElement('div');
const endY = DUMMY_CORD.getAttribute('y2');
const endX = DUMMY_CORD.getAttribute('x2');
// set init position
const RESET = () => {
  set(PROXY, {
    x: endX,
    y: endY });

};

const AUDIO = {
  BEAR_LONG: new Audio('https://assets.codepen.io/605876/bear-groan-long.mp3'),
  BEAR_SHORT: new Audio(
  'https://assets.codepen.io/605876/bear-groan-short.mp3'),

  DOOR_OPEN: new Audio('https://assets.codepen.io/605876/door-open.mp3'),
  DOOR_CLOSE: new Audio('https://assets.codepen.io/605876/door-close.mp3'),
  CLICK: new Audio('https://assets.codepen.io/605876/click.mp3') };

const STATE = {
  ON: false,
  ANGER: 0 };

set(PAW, {
  transformOrigin: '50% 50%',
  xPercent: -30 });

set('.bulb', { z: 10 });
set(ARMS, {
  xPercent: 10,
  rotation: -90,
  transformOrigin: '100% 50%',
  yPercent: -2,
  display: 'block' });

const CONFIG = {
  ARM_DUR: 0.4,
  CLENCH_DUR: 0.1,
  BEAR_START: 40,
  BEAR_FINISH: -55,
  BEAR_ROTATE: -50,
  DOOR_OPEN: 25,
  INTRO_DELAY: 1,
  BEAR_APPEARANCE: 2,
  SLAM: 3,
  BROWS: 4 };

set('.bear__brows', { display: 'none' });
set('.bear', {
  rotate: CONFIG.BEAR_ROTATE,
  xPercent: CONFIG.BEAR_START,
  transformOrigin: '50% 50%',
  scale: 0,
  display: 'block' });


RESET();

const CORD_TL = () => {
  const TL = timeline({
    paused: false,
    onStart: () => {
      // Hook this up to localStorage for jhey.dev
      STATE.ON = !STATE.ON;
      INPUT.checked = !STATE.ON;
      set(document.documentElement, { '--on': STATE.ON ? 1 : 0 });
      set([DUMMY], { display: 'none' });
      set(CORDS[0], { display: 'block' });
      AUDIO.CLICK.play();
    },
    onComplete: () => {
      // BEAR_TL.restart()
      set([DUMMY], { display: 'block' });
      set(CORDS[0], { display: 'none' });
      RESET();
    } });

  for (let i = 1; i < CORDS.length; i++) {
    TL.add(
    to(CORDS[0], {
      morphSVG: CORDS[i],
      duration: CORD_DURATION,
      repeat: 1,
      yoyo: true }));


  }
  return TL;
};

/**
 * Mess around with the actial input toggling here.
 */
const BEAR_TL = () => {
  const ARM_SWING = STATE.ANGER > 4 ? 0.2 : CONFIG.ARM_DUR;
  const SLIDE = STATE.ANGER > CONFIG.BROWS + 3 ? 0.2 : random(0.2, 0.6);
  const CLOSE_DELAY = STATE.ANGER >= CONFIG.INTRO_DELAY ? random(0.2, 2) : 0;
  const TL = timeline({
    paused: false }).

  to('.door', {
    onStart: () => AUDIO.DOOR_OPEN.play(),
    rotateY: 25,
    duration: 0.2 }).

  add(
  STATE.ANGER >= CONFIG.BEAR_APPEARANCE && Math.random() > 0.25 ?
  to('.bear', {
    onStart: () => {
      if (Math.random() > 0.5) {
        // delayedCall(random(0, 1.5), () => {
        //   AUDIO[
        //     STATE.ANGER >= CONFIG.BROWS && Math.random() > 0.5
        //       ? 'BEAR_LONG'
        //       : 'BEAR_SHORT'
        //   ].play()
        // })
      }
      set('.bear', { scale: 1 });
    },
    xPercent: CONFIG.BEAR_FINISH,
    repeat: 1,
    repeatDelay: 1,
    yoyo: true,
    duration: SLIDE }) :

  () => {}).

  to(ARMS, {
    delay: CLOSE_DELAY,
    duration: ARM_SWING,
    rotation: 0,
    xPercent: 0,
    yPercent: 0 }).

  to(
  [PAW, '#knuckles'],
  {
    duration: CONFIG.CLENCH_DUR,
    xPercent: (_, target) => target.id === 'knuckles' ? 10 : 0 },

  `>-${ARM_SWING * 0.5}`).

  to(ARMS, {
    duration: ARM_SWING * 0.5,
    rotation: 5 }).

  to(ARMS, {
    rotation: -90,
    xPercent: 10,
    duration: ARM_SWING,
    onComplete: () => {
      to('.door', {
        onComplete: () => AUDIO.DOOR_CLOSE.play(),
        duration: 0.2,
        rotateY: 0 });

    } }).

  to(
  DUMMY_CORD,
  {
    duration: CONFIG.CLENCH_DUR,
    attr: {
      x2: parseInt(endX, 10) + 20,
      y2: parseInt(endY, 10) + 60 } },


  '<').

  to(
  DUMMY_CORD,
  {
    duration: CONFIG.CLENCH_DUR,
    attr: {
      x2: endX,
      y2: endY } },


  '>').

  to(
  [PAW, '#knuckles'],
  {
    duration: CONFIG.CLENCH_DUR,
    xPercent: (_, target) => target.id === 'knuckles' ? 0 : -28 },

  '<').

  add(() => CORD_TL(), '<');
  return TL;
};

const IMPOSSIBLE_TL = () =>
timeline({
  onStart: () => set(HIT, { display: 'none' }),
  onComplete: () => {
    set(HIT, { display: 'block' });
    if (Math.random() > 0) STATE.ANGER = STATE.ANGER + 1;
    if (STATE.ANGER >= CONFIG.BROWS) set('.bear__brows', { display: 'block' });
  } }).

add(CORD_TL()).
add(BEAR_TL());

Draggable.create(PROXY, {
  trigger: HIT,
  type: 'x,y',
  onPress: e => {
    startX = e.x;
    startY = e.y;
    RESET();
  },
  onDrag: function () {
    set(DUMMY_CORD, {
      attr: {
        x2: this.x,
        y2: this.y } });


  },
  onRelease: function (e) {
    const DISTX = Math.abs(e.x - startX);
    const DISTY = Math.abs(e.y - startY);
    const TRAVELLED = Math.sqrt(DISTX * DISTX + DISTY * DISTY);
    to(DUMMY_CORD, {
      attr: { x2: endX, y2: endY },
      duration: CORD_DURATION,
      onComplete: () => {
        if (TRAVELLED > 50) {
          IMPOSSIBLE_TL();
        } else {
          RESET();
        }
      } });

  } });

style.css:
* {
  box-sizing: border-box;
}
:root {
  --depth: 5vmin;
  --on: 0;
  --size: 25vmin;
  --bg: hsl(calc(200 - (var(--on) * 160)), calc((20 + (var(--on) * 50)) * 1%), calc((20 + (var(--on) * 60)) * 1%));
  --cord: hsl(0, 0%, calc((60 - (var(--on) * 50)) * 1%));
  --stroke: hsl(0, 0%, calc((60 - (var(--on) * 50)) * 1%));
  --shine: hsla(0, 0%, 100%, calc(0.75 - (var(--on) * 0.5)));
  --cap: hsl(0, 0%, calc((40 + (var(--on) * 30)) * 1%));
  --filament: hsl(45, calc(var(--on) * 80%), calc((25 + (var(--on) * 75)) * 1%));
}
body {
  min-height: 100vh;
  display: flex;
  align-items: center;
  justify-content: center;
  background: var(--bg);
  overflow: hidden;
}
label {
  position: absolute;
  opacity: 0.5;
  height: 100%;
  width: 100%;
  top: 0;
  left: 0;
  z-index: 2;
}
input {
  height: 0;
  width: 0;
  position: fixed;
  left: 100%;
  transform: scale(0);
}
.toggle {
  height: var(--size);
  width: var(--size);
  transform: translate(-50%, -100%);
  z-index: 2;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate3d(-50%, -100%, calc(var(--depth) * 3));
}
.toggle-scene {
  overflow: visible !important;
  width: 100%;
  position: absolute;
}
.toggle-scene__arm {
  display: none;
}
.toggle-scene__cord {
  stroke: var(--cord);
  cursor: move;
}
.toggle-scene__cord:nth-of-type(1) {
  display: none;
}
.toggle-scene__cord:nth-of-type(2),
.toggle-scene__cord:nth-of-type(3),
.toggle-scene__cord:nth-of-type(4),
.toggle-scene__cord:nth-of-type(5) {
  display: none;
}
.toggle-scene__cord-end {
  stroke: var(--cord);
  fill: var(--cord);
}
.toggle-scene__dummy-cord {
  stroke-width: 6;
  stroke: var(--cord);
}
.bulb__filament {
  stroke: var(--filament);
}
.bulb__shine {
  stroke: var(--shine);
}
.bulb__flash {
  stroke: #f5e0a3;
  display: none;
}
.bulb__bulb {
  stroke: var(--stroke);
  fill: hsla(calc(180 - (95 * var(--on))), 80%, 80%, calc(0.1 + (0.4 * var(--on))));
}
.bulb__cap {
  fill: var(--cap);
}
.bulb__cap-shine {
  fill: var(--shine);
}
.bulb__cap-outline {
  stroke: var(--stroke);
}
.bear {
  display: none;
}
.bear__fur {
  fill: #784421;
}
.bear__pad {
  fill: #deaa87;
}
.doorway {
  position: absolute;
  top: 50%;
  height: calc(var(--size) * 4);
  width: calc(var(--size) * 1.5);
  transform: translate(0, calc(var(--size) * -0.75));
  left: calc(50% + (var(--size) * 0.5));
  -webkit-clip-path: inset(0 0 0 -200%);
  clip-path: inset(0 0 0 -200%);
}
.doorway__opening {
  height: 100%;
  width: 100%;
  position: absolute;
  background: #1a1a1a;
  transform: translate3d(0, 0, calc(var(--depth) * -1));
}
.bear {
  position: absolute;
  top: 10%;
  width: var(--size);
}
.door {
  --panel: hsl(30, 20%, calc(12% + (var(--on) * 40%)));
  height: 100%;
  position: absolute;
  width: 100%;
  transform-origin: 100% 50%;
  transform-style: preserve-3d;
  transform: rotateY(0deg);
}
.door__panel {
  width: 30%;
  height: 35%;
  position: absolute;
  border: 1vmin var(--panel) solid;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%) translate(var(--x), var(--y));
}
.door__panel:nth-of-type(1) {
  --x: -70%;
  --y: -70%;
}
.door__panel:nth-of-type(2) {
  --x: 70%;
  --y: -70%;
}
.door__panel:nth-of-type(3) {
  --x: -70%;
  --y: 70%;
}
.door__panel:nth-of-type(4) {
  --x: 70%;
  --y: 70%;
}
.door__handle {
  height: 4vmin;
  width: 4vmin;
  position: absolute;
  left: 10%;
  top: 50%;
  transform: translate3d(0, -50%, 1vmin);
}
.door__handle > div {
  position: absolute;
  height: 100%;
  width: 100%;
  background-color: hsl(45, 70%, calc((var(--lightness, 20%)) + (var(--on) * 40%)));
}
.door__handle > div:nth-of-type(1) {
  --lightness: 25%;
}
.door__handle > div:nth-of-type(2) {
  --lightness: 30%;
  transform: translate3d(0, 0, calc(var(--depth) * 1));
}
.door__side {
  position: absolute;
}
.door__side:nth-of-type(1) {
  --lightness: 20%;
  height: 100%;
  width: 100%;
  transform: translate3d(0, 0, 0);
  z-index: 3;
  background-color: hsl(30, 20%, calc((var(--lightness, 20%)) + (var(--on) * 40%)));
}
.door__side:nth-of-type(2) {
  --lightness: 10%;
  height: 100%;
  width: 100%;
  transform: translate3d(0, 0, calc(var(--depth) * -1));
}
.door__side {
  background-color: hsl(30, 20%, calc((var(--lightness, 20%)) + (var(--on) * 40%)));
}
